from sympy import factorint
from sympy.ntheory.factor_ import digits
def A051696(n):
    c = 1
    for p, e in factorint(n).items():
        c *= p**min(e*n,(n-sum(digits(n,p)[1:]))//(p-1))
    return c # _Chai Wah Wu_, May 02 2026

